import React from "react";
import { Card } from "react-bootstrap";

const product = (pro) => {
  return (
    <>
      <Card className="my-3 pd-3 rounded ">
        <a href={`/product/ ${pro._id}`}>
          <Card.Img src={pro.image} varient="top" />
        </a>
        <Card.Body>
          <a href={`/product/ ${pro._id}`}>
            <Card.Title as="div">
              <strong>{pro.name}</strong>
            </Card.Title>
          </a>

          <Card.Text as="h1">{pro.price}</Card.Text>
        </Card.Body>
      </Card>
    </>
  );
};

export default product;
